#ifndef fp
#define fp float
#endif

#ifndef NUMBER_THREADS
#define NUMBER_THREADS 256
#endif

__kernel void extract_kernel(long d_Ne, fp *d_I) {
    int ei = get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei]);
    }
}

__kernel void prepare_kernel(long d_Ne, fp *d_I, fp *d_sums, fp *d_sums2) {
    int ei = get_global_id(0);
    if (ei < d_Ne) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

__kernel void reduce_kernel(long d_Ne, long d_no, int d_mul, fp *d_sums, fp *d_sums2, int blocks2_work_size) {
    int ei = get_global_id(0);
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int nf = NUMBER_THREADS - (get_num_groups(0) * NUMBER_THREADS - d_no);
    int df = 0;

    local fp d_psum[NUMBER_THREADS];
    local fp d_psum2[NUMBER_THREADS];

    int i;

    if (ei < d_no) {
        d_psum[tx] = d_sums[ei * d_mul];
        d_psum2[tx] = d_sums2[ei * d_mul];
    }

    if (nf == NUMBER_THREADS) {
        for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
            if ((tx + 1) % i == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (NUMBER_THREADS - 1)) {
            d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
            d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
        }
    } else {
        if (bx != (get_num_groups(0) - 1)) {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if ((tx + 1) % i == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (NUMBER_THREADS - 1)) {
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        } else {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (i = 2; i <= df; i = 2 * i) {
                if ((tx + 1) % i == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (df - 1)) {
                for (i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }

                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        }
    }
}

__kernel void srad_kernel(fp lambda, int Nr, int Nc, long Ne,
                          const int *d_iN, const int *d_iS,
                          const int *d_jE, const int *d_jW,
                          fp *d_dN, fp *d_dS, fp *d_dW, fp *d_dE,
                          fp q0sqr, fp *d_c, fp *d_I) {
    int ei = get_global_id(0);
    if (ei < Ne) {
        int i = ei / Nc;
        int j = ei % Nc;
        int k = ei;

        fp Jc = d_I[k];

        d_dN[k] = d_I[d_iN[i] * Nc + j] - Jc;
        d_dS[k] = d_I[d_iS[i] * Nc + j] - Jc;
        d_dW[k] = d_I[i * Nc + d_jW[j]] - Jc;
        d_dE[k] = d_I[i * Nc + d_jE[j]] - Jc;

        fp G2 = (d_dN[k] * d_dN[k] + d_dS[k] * d_dS[k] +
                d_dW[k] * d_dW[k] + d_dE[k] * d_dE[k]) / (Jc * Jc);

        fp L = (d_dN[k] + d_dS[k] + d_dW[k] + d_dE[k]) / Jc;

        fp num = (0.5 * G2) - ((1.0 / 16.0) * (L * L));
        fp den = 1 + (0.25 * L);
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1 + q0sqr));
        d_c[k] = 1.0 / (1.0 + den);

        if (d_c[k] < 0) d_c[k] = 0;
        else if (d_c[k] > 1) d_c[k] = 1;
    }
}

__kernel void srad2_kernel(fp lambda, int Nr, int Nc, long Ne,
                           const int *d_iN, const int *d_iS,
                           const int *d_jE, const int *d_jW,
                           fp *d_dN, fp *d_dS, fp *d_dW, fp *d_dE,
                           fp *d_c, fp *d_I) {
    int ei = get_global_id(0);
    if (ei < Ne) {
        int i = ei / Nc;
        int j = ei % Nc;
        int k = ei;

        fp cN = d_c[k];
        fp cS = d_c[d_iS[i] * Nc + j];
        fp cW = d_c[k];
        fp cE = d_c[i * Nc + d_jE[j]];

        fp D = cN * d_dN[k] + cS * d_dS[k] + cW * d_dW[k] + cE * d_dE[k];

        d_I[k] = d_I[k] + 0.25 * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne, fp *d_I) {
    int ei = get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255;
    }
}
